Here is an example of how you can design a function in Python to evaluate a given mathematical expression containing addition, subtraction, multiplication, and division operations:

```python
def evaluate_expression(expression):
    # Remove any whitespace from the expression
    expression = expression.replace(" ", "")

    # Define a helper function to perform the calculations
    def calculate(expression):
        stack = []
        current_num = 0
        operator = "+"

        for i, char in enumerate(expression):
            if char.isdigit():
                current_num = (current_num * 10) + int(char)

            if char == "(":
                # Find the closing parenthesis
                count = 1
                j = i + 1
                while j < len(expression):
                    if expression[j] == "(":
                        count += 1
                    elif expression[j] == ")":
                        count -= 1
                        if count == 0:
                            break
                    j += 1

                # Recursively calculate the value inside the parentheses
                current_num = calculate(expression[i+1:j])

            if (not char.isdigit() and char != ".") or i == len(expression) - 1:
                if operator == "+":
                    stack.append(current_num)
                elif operator == "-":
                    stack.append(-current_num)
                elif operator == "*":
                    stack.append(stack.pop() * current_num)
                elif operator == "/":
                    stack.append(stack.pop() / current_num)

                current_num = 0
                operator = char

        return sum(stack)

    return calculate(expression)
```

You can then test the function with your example:

